select stk.id, m.code materialCode, m.name materialName, stk.bill_no billNo, stk.bill_date billDate, stk.bill_type billType, b.qty materialQty, IFNULL(b.unit_price, CASE WHEN b.amt IS NOT NULL AND b.qty IS NOT NULL AND b.qty > 0 THEN ROUND(b.amt / b.qty, 2) ELSE NULL END) unitPrice, b.amt materialAmt, b.batch_no batchNo, b.batch_number batchNumber, b.begin_time beginTime, b.end_time endTime, m.speci materialSpeci, m.model materialModel, u.unit_name unitName, f.factory_name factoryName, fc.finance_category_name financeCategoryName, s.name supplierName, d.name departmentName, w.name warehouseName, b.material_id materialId, m.register_no materialRegisterNo, m.package_speci materialPackageSpeci, m.is_way materialIsWay, wc.warehouse_category_name materialWarehouseCategoryName, stk.create_time createTime, cu.nick_name createrNickName, cu.user_name createrUserName, stk.audit_date auditDate, au.nick_name auditNickName, au.user_name auditUserName from stk_io_bill stk left join stk_io_bill_entry b on b.paren_id = stk.id and (b.del_flag is null or b.del_flag != 1) left join fd_supplier s on stk.suppler_id = s.id left join fd_department d on stk.department_id = d.id left join fd_warehouse w on stk.warehouse_id = w.id left join fd_material m on b.material_id = m.id left join fd_warehouse_category wc on m.storeroom_id = wc.warehouse_category_id left join fd_factory f on f.factory_id = m.factory_id left join fd_unit u on u.unit_id = m.unit_id left join fd_finance_category fc on fc.finance_category_id = m.finance_category_id left join sys_user cu on stk.create_by = cu.user_id left join sys_user au on stk.audit_by = au.user_id where (stk.del_flag = 0 or stk.del_flag is null) and stk.tenant_id = #{scopedTenantId} and stk.bill_type in (201,401) and stk.bill_no like concat('%', #{billNo}, '%') and stk.warehouse_id = #{warehouseId} and stk.department_id = #{departmentId} and m.id = #{materialId} and (m.name like concat('%', #{materialNameLike}, '%') or m.code like concat('%', #{materialNameLike}, '%') or m.referred_name like concat('%', #{materialNameLike}, '%')) and m.speci like concat('%', #{materialSpeciLike}, '%') and m.model like concat('%', #{materialModelLike}, '%')
