bill_no = #{billNo}, ref_bill_no = #{refBillNo}, suppler_id = #{supplerId}, bill_date = #{billDate}, warehouse_id = #{warehouseId}, department_id = #{departmentId}, bill_status = #{billStatus}, user_id = #{userId}, bill_type = #{billType}, del_flag = #{delFlag}, audit_date = #{auditDate}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark}, del_person = #{delPerson}, telephone = #{telephone}, total_amount = #{totalAmount}, invoice_number = #{invoiceNumber}, invoice_amount = #{invoiceAmount}, invoice_time = #{invoiceTime}, pro_person = #{proPerson}, return_reason = #{returnReason}, is_month_init = #{isMonthInit}, receipt_confirm_status = #{receiptConfirmStatus}, audit_by = #{auditBy}, tenant_id = #{scopedTenantId}, delete_by = #{deleteBy}, delete_time = #{deleteTime}, settlement_type = #{settlementType},
