select id,materialCode,materialName,billNo,billDate,billType,materialQty,price,materialAmt, batchNo,batchNumber,beginTime,endTime,materialSpeci,materialModel,unitName,factoryName, financeCategoryName,departmentName,warehouseName,supplierName from ( select stk.id,m.code materialCode,m.name materialName, stk.bill_no billNo, stk.bill_date billDate, stk.bill_type billType,b.qty materialQty, b.price price, b.amt materialAmt, b.batch_no batchNo, b.batch_number batchNumber, b.begin_time beginTime, b.end_time endTime,m.speci materialSpeci,m.model materialModel,u.unit_name unitName, f.factory_name factoryName,fc.finance_category_name financeCategoryName, d.name departmentName, w.name warehouseName,s.name supplierName from stk_io_bill stk left join stk_io_bill_entry b on b.paren_id = stk.id left join fd_department d on stk.department_id = d.id left join fd_warehouse w on stk.warehouse_id = w.id left join fd_material m on b.material_id = m.id left join fd_supplier s on s.id = m.supplier_id left join fd_factory f on f.factory_id = m.factory_id left join fd_unit u on u.unit_id = m.unit_id left join fd_finance_category fc on fc.finance_category_id = m.finance_category_id where stk.del_flag != 1 and stk.bill_status = 2 and stk.bill_type in (101,301) and stk.tenant_id = #{scopedTenantId} and stk.warehouse_id = #{warehouseId} union select stk.id,m.code materialCode,m.name materialName, stk.bill_no billNo, stk.bill_date billDate, stk.bill_type billType,b.qty materialQty, b.unit_price price, b.amt materialAmt, b.batch_no batchNo, b.batch_number batchNumber, b.begin_time beginTime, b.end_time endTime,m.speci materialSpeci,m.model materialModel,u.unit_name unitName, f.factory_name factoryName,fc.finance_category_name financeCategoryName, d.name departmentName, w.name warehouseName,s.name supplierName from stk_io_bill stk left join stk_io_bill_entry b on b.paren_id = stk.id left join fd_department d on stk.department_id = d.id left join fd_warehouse w on stk.warehouse_id = w.id left join fd_material m on b.material_id = m.id left join fd_supplier s on s.id = m.supplier_id left join fd_factory f on f.factory_id = m.factory_id left join fd_unit u on u.unit_id = m.unit_id left join fd_finance_category fc on fc.finance_category_id = m.finance_category_id where stk.del_flag != 1 and stk.bill_status = 2 and stk.bill_type in (201,401) and stk.tenant_id = #{scopedTenantId} and stk.warehouse_id = #{warehouseId} union -- 调拨单：调出仓库记录（数量为负数，表示出库） select stk.id,m.code materialCode,m.name materialName, stk.bill_no billNo, stk.bill_date billDate, stk.bill_type billType,-b.qty materialQty, b.unit_price price, -b.amt materialAmt, b.batch_no batchNo, b.batch_number batchNumber, b.begin_time beginTime, b.end_time endTime,m.speci materialSpeci,m.model materialModel,u.unit_name unitName, f.factory_name factoryName,fc.finance_category_name financeCategoryName, d.name departmentName, w.name warehouseName,s.name supplierName from stk_io_bill stk left join stk_io_bill_entry b on b.paren_id = stk.id left join fd_department d on stk.department_id = d.id left join fd_warehouse w on stk.warehouse_id = w.id left join fd_material m on b.material_id = m.id left join fd_supplier s on s.id = m.supplier_id left join fd_factory f on f.factory_id = m.factory_id left join fd_unit u on u.unit_id = m.unit_id left join fd_finance_category fc on fc.finance_category_id = m.finance_category_id where stk.del_flag != 1 and stk.bill_status = 2 and stk.bill_type = 501 and stk.bill_no not like 'JS%' and stk.tenant_id = #{scopedTenantId} and stk.warehouse_id = #{warehouseId} union -- 调拨单：调入仓库记录（数量为正数，表示入库） select stk.id,m.code materialCode,m.name materialName, stk.bill_no billNo, stk.bill_date billDate, stk.bill_type billType,b.qty materialQty, b.unit_price price, b.amt materialAmt, b.batch_no batchNo, b.batch_number batchNumber, b.begin_time beginTime, b.end_time endTime,m.speci materialSpeci,m.model materialModel,u.unit_name unitName, f.factory_name factoryName,fc.finance_category_name financeCategoryName, d.name departmentName, tw.name warehouseName,s.name supplierName from stk_io_bill stk left join stk_io_bill_entry b on b.paren_id = stk.id left join fd_department d on stk.department_id = d.id left join fd_warehouse w on stk.warehouse_id = w.id left join fd_warehouse tw on stk.department_id = tw.id left join fd_material m on b.material_id = m.id left join fd_supplier s on s.id = m.supplier_id left join fd_factory f on f.factory_id = m.factory_id left join fd_unit u on u.unit_id = m.unit_id left join fd_finance_category fc on fc.finance_category_id = m.finance_category_id where stk.del_flag != 1 and stk.bill_status = 2 and stk.bill_type = 501 and stk.bill_no not like 'JS%' and stk.tenant_id = #{scopedTenantId} and stk.department_id = #{warehouseId} union select a.id,m.code materialCode,m.name materialName, a.stock_no billNo, a.stock_date billDate, a.stock_type billType,b.qty materialQty, b.price price, b.amt materialAmt, b.batch_no batchNo, b.batch_number batchNumber, b.begin_time beginTime, b.end_time endTime,m.speci materialSpeci,m.model materialModel,u.unit_name unitName, f.factory_name factoryName,fc.finance_category_name financeCategoryName, d.name departmentName, w.name warehouseName,s.name supplierName from stk_io_stocktaking a left join stk_io_stocktaking_entry b on b.paren_id = a.id left join fd_department d on a.department_id = d.id left join fd_warehouse w on a.warehouse_id = w.id left join fd_material m on b.material_id = m.id left join fd_supplier s on s.id = m.supplier_id left join fd_factory f on f.factory_id = m.factory_id left join fd_unit u on u.unit_id = m.unit_id left join fd_finance_category fc on fc.finance_category_id = m.finance_category_id where a.del_flag != 1 and a.stock_status = 2 and a.tenant_id = #{scopedTenantId} ) t
and billNo like concat('%', #{billNo}, '%') and materialName like concat('%', #{materialName}, '%') and warehouseName like concat('%', #{warehouseName}, '%') and billDate >= #{beginDate} and billDate <= #{endDate}
and billType in
#{type}
and billType = #{billType}


SELECT 
    m.id materialId, m.code materialCode, m.name materialName,
    m.speci materialSpeci, m.model materialModel,
    u.unit_name unitName, AVG(b.unit_price) unitPrice,
    SUM(b.qty) totalQty, SUM(b.amt) totalAmt,
    ROUND((SUM(b.amt) / (SELECT IFNULL(SUM(amt), 1) FROM stk_io_bill_entry entry
        INNER JOIN stk_io_bill bill ON bill.id = entry.paren_id
        WHERE bill.del_flag != 1 AND bill.bill_status = 2 AND bill.bill_type = 201
        AND bill.tenant_id = #{scopedTenantId}
        AND entry.del_flag != 1
         AND bill.warehouse_id = #{warehouseId}
         AND bill.department_id = #{departmentId}
         AND bill.bill_date >= #{beginDate}
         AND bill.bill_date <= #{endDate}
    )) * 100, 2) as percentage,
    f.factory_name factoryName, s.name supplierName
FROM stk_io_bill stk
LEFT JOIN stk_io_bill_entry b ON b.paren_id = stk.id AND b.del_flag != 1
LEFT JOIN fd_material m ON b.material_id = m.id
LEFT JOIN fd_unit u ON m.unit_id = u.unit_id
LEFT JOIN fd_factory f ON m.factory_id = f.factory_id
LEFT JOIN fd_supplier s ON m.supplier_id = s.id
WHERE stk.del_flag != 1 
  AND stk.tenant_id = #{scopedTenantId}
  AND stk.bill_status = 2 
  AND stk.bill_type = 201
 AND stk.warehouse_id = #{warehouseId}
 AND stk.department_id = #{departmentId}
 AND stk.bill_date >= #{beginDate}
 AND stk.bill_date <= #{endDate}
GROUP BY m.id, m.code, m.name, m.speci, m.model, u.unit_name, f.factory_name, s.name
ORDER BY totalAmt DESC
